import UIKit
import Foundation

class PromoLinkHandler {
    static let shared = PromoLinkHandler()
    
    private init() {}
    
    func handleUniversalLink(_ url: URL) -> Bool {
        guard url.scheme == "https" && url.host == "myapp.com" else {
            return false
        }
        
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let path = components.path.addingPercentEncoding(withAllowedCharacters: .urlPathAllowed),
              path == "/promo" else {
            return false
        }
        
        guard let promoCode = getParameter(from: url, forKey: "code"),
              let discountString = getParameter(from: url, forKey: "discount"),
              let discount = Int(discountString),
              discount >= 0 && discount <= 100 else {
            return false
        }
        
        applyPromoCode(promoCode: promoCode, discount: discount)
        return true
    }
    
    private func getParameter(from url: URL, forKey key: String) -> String? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems else {
            return nil
        }
        
        return queryItems.first { $0.name == key }?.value
    }
    
    private func applyPromoCode(promoCode: String, discount: Int) {
        guard !promoCode.isEmpty else { return }
        
        let userDefaults = UserDefaults.standard
        let promoKey = "applied_promo_code"
        let discountKey = "promo_discount"
        
        if let existingCode = userDefaults.string(forKey: promoKey),
           existingCode == promoCode {
            return
        }
        
        userDefaults.set(promoCode, forKey: promoKey)
        userDefaults.set(discount, forKey: discountKey)
        userDefaults.synchronize()
        
        NotificationCenter.default.post(name: NSNotification.Name("PromoCodeApplied"), object: nil)
    }
}

extension UIApplication {
